logger = logging.getLogger(__name__)


class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, authorized_tokens: Set[str] = None, required_headers: Dict[str, str] = None):
        """
        Initialize the authorization service.
        
        Args:
            authorized_tokens: Set of valid authorization tokens
            required_headers: Dictionary of required headers and their expected values
        """
        self.authorized_tokens = authorized_tokens or set()
        self.required_headers = required_headers or {}
        
        # Load tokens from environment if available
        env_tokens = os.getenv('AUTHORIZED_TOKENS', '')
        if env_tokens:
            self.authorized_tokens.update(token.strip() for token in env_tokens.split(',') if token.strip())
        
        logger.info(f"Authorization service initialized with {len(self.authorized_tokens)} tokens")

    def Check(self, request: external_auth_pb2.CheckRequest, context: grpc.ServicerContext) -> external_auth_pb2.CheckResponse:
        """
        Process authorization check request from Envoy.
        
        Args:
            request: CheckRequest from Envoy containing request attributes
            context: gRPC context
            
        Returns:
            CheckResponse with authorization decision
        """
        try:
            # Extract request attributes
            attributes = request.attributes
            http_request = attributes.request.http
            
            # Get headers (case-insensitive)
            headers = {k.lower(): v for k, v in http_request.headers.items()}
            
            # Log request details (sanitized)
            logger.info(f"Authorization check for path: {http_request.path}, method: {http_request.method}")
            
            # Perform authorization checks
            auth_result = self._authorize(headers, http_request)
            
            if auth_result['authorized']:
                return self._create_ok_response(auth_result.get('headers_to_add', {}))
            else:
                return self._create_denied_response(
                    auth_result.get('status_code', 403),
                    auth_result.get('message', 'Unauthorized'),
                    auth_result.get('headers_to_add', {})
                )
                
        except Exception as e:
            logger.error(f"Error processing authorization request: {str(e)}", exc_info=True)
            return self._create_denied_response(500, "Internal authorization error")

    def _authorize(self, headers: Dict[str, str], http_request) -> Dict:
        """
        Perform authorization logic.
        
        Args:
            headers: Request headers (lowercase keys)
            http_request: HTTP request attributes
            
        Returns:
            Dictionary with authorization result
        """
        # Check for authorization header
        auth_header = headers.get('authorization', '')
        
        if not auth_header:
            logger.warning("Missing authorization header")
            return {
                'authorized': False,
                'status_code': 401,
                'message': 'Missing authorization header',
                'headers_to_add': {'www-authenticate': 'Bearer'}
            }
        
        # Extract token from Bearer scheme
        token = self._extract_bearer_token(auth_header)
        
        if not token:
            logger.warning("Invalid authorization header format")
            return {
                'authorized': False,
                'status_code': 401,
                'message': 'Invalid authorization header format',
                'headers_to_add': {'www-authenticate': 'Bearer'}
            }
        
        # Validate token
        if not self._validate_token(token):
            logger.warning(f"Invalid or unauthorized token")
            return {
                'authorized': False,
                'status_code': 403,
                'message': 'Invalid or unauthorized token'
            }
        
        # Check required headers
        for header_name, expected_value in self.required_headers.items():
            actual_value = headers.get(header_name.lower(), '')
            if actual_value != expected_value:
                logger.warning(f"Required header mismatch: {header_name}")
                return {
                    'authorized': False,
                    'status_code': 403,
                    'message': f'Missing or invalid required header: {header_name}'
                }
        
        # Additional custom authorization logic can be added here
        # For example: role-based access control, rate limiting, etc.
        
        logger.info("Authorization successful")
        return {
            'authorized': True,
            'headers_to_add': {
                'x-auth-user': 'authenticated',
                'x-auth-method': 'bearer-token'
            }
        }

    def _extract_bearer_token(self, auth_header: str) -> str:
        """
        Extract token from Bearer authorization header.
        
        Args:
            auth_header: Authorization header value
            
        Returns:
            Extracted token or empty string
        """
        parts = auth_header.split(' ', 1)
        if len(parts) == 2 and parts[0].lower() == 'bearer':
            return parts[1].strip()
        return ''

    def _validate_token(self, token: str) -> bool:
        """
        Validate the provided token.
        
        Args:
            token: Token to validate
            
        Returns:
            True if token is valid, False otherwise
        """
        # Input validation
        if not token or len(token) > 1024:  # Prevent extremely long tokens
            return False
        
        # Check against authorized tokens
        return token in self.authorized_tokens

    def _create_ok_response(self, headers_to_add: Dict[str, str] = None) -> external_auth_pb2.CheckResponse:
        """
        Create a successful authorization response.
        
        Args:
            headers_to_add: Optional headers to add to the request
            
        Returns:
            CheckResponse indicating success
        """
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.OK
        
        if headers_to_add:
            ok_response = external_auth_pb2.OkHttpResponse()
            for key, value in headers_to_add.items():
                header = ok_response.headers.add()
                header.header.key = key
                header.header.value = value
            response.ok_response.CopyFrom(ok_response)
        
        return response

    def _create_denied_response(self, status_code: int, message: str, headers_to_add: Dict[str, str] = None) -> external_auth_pb2.CheckResponse:
        """
        Create a denied authorization response.
        
        Args:
            status_code: HTTP status code
            message: Denial message
            headers_to_add: Optional headers to add to the response
            
        Returns:
            CheckResponse indicating denial
        """
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.PERMISSION_DENIED
        response.status.message = message
        
        denied_response = external_auth_pb2.DeniedHttpResponse()
        denied_response.status.code = http_status_pb2.StatusCode.Value(f'_{status_code}') if hasattr(http_status_pb2.StatusCode, f'_{status_code}') else http_status_pb2.StatusCode.Forbidden
        denied_response.body = message
        
        if headers_to_add:
            for key, value in headers_to_add.items():
                header = denied_response.headers.add()
                header.key = key
                header.value = value
        
        response.denied_response.CopyFrom(denied_response)
        
        return response


